import { useState, useEffect, useCallback } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import axios from 'axios';
import './Dashboard.css';

const STATUS_OPTIONS = ['Open', 'In Progress', 'Closed'];

export default function Dashboard() {
  const { user, logout } = useAuth();
  const location = useLocation();
  const navigate = useNavigate();
  const context = location.state;

  const [tab, setTab] = useState('create');
  const [rows, setRows] = useState([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [msg, setMsg] = useState({ text: '', type: '' });

  useEffect(() => {
    if (!context) navigate('/select');
  }, [context, navigate]);

  const showMsg = (text, type = 'success') => {
    setMsg({ text, type });
    setTimeout(() => setMsg({ text: '', type: '' }), 3000);
  };

  const fetchRows = useCallback(async () => {
    if (!context) return;
    setLoading(true);
    try {
      const res = await axios.get('/api/observations', {
        params: { company: context.company, financialYear: context.financialYear, business: context.business }
      });
      setRows(res.data);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  }, [context]);

  useEffect(() => { fetchRows(); }, [fetchRows]);

  const addRow = async () => {
    setSaving(true);
    try {
      const payload = {
        company: context.company,
        financialYear: context.financialYear,
        business: context.business,
        area: '', observation: '', managerComment: '',
        personResponsibilityAsPerAC: '', personResponsible: '',
        status: 'Open', closingPeriod: '', closedOn: '',
      };
      const res = await axios.post('/api/observations', payload);
      setRows(r => [...r, res.data]);
      showMsg('Row added!');
    } catch (e) {
      showMsg('Error adding row', 'error');
    } finally {
      setSaving(false);
    }
  };

  const updateCell = (index, field, value) => {
    setRows(r => r.map((row, i) => i === index ? { ...row, [field]: value } : row));
  };

  const handleBlur = async (index) => {
    const row = rows[index];
    if (!row._id) return;
    try {
      await axios.put(`/api/observations/${row._id}`, {
        company: context.company,
        financialYear: context.financialYear,
        business: context.business,
        area: row.area,
        observation: row.observation,
        managerComment: row.managerComment,
        personResponsibilityAsPerAC: row.personResponsibilityAsPerAC,
        personResponsible: row.personResponsible,
        status: row.status,
        closingPeriod: row.closingPeriod,
        closedOn: row.closedOn,
      });
    } catch (e) {
      console.error('Auto-save failed', e);
    }
  };

  const handleStatusChange = async (index, value) => {
    updateCell(index, 'status', value);
    const row = { ...rows[index], status: value };
    if (!row._id) return;
    try {
      await axios.put(`/api/observations/${row._id}`, {
        company: context.company,
        financialYear: context.financialYear,
        business: context.business,
        area: row.area,
        observation: row.observation,
        managerComment: row.managerComment,
        personResponsibilityAsPerAC: row.personResponsibilityAsPerAC,
        personResponsible: row.personResponsible,
        status: value,
        closingPeriod: row.closingPeriod,
        closedOn: row.closedOn,
      });
    } catch (e) {
      console.error('Status save failed', e);
    }
  };

  const deleteRow = async (index) => {
    const row = rows[index];
    if (!window.confirm('Delete this row?')) return;
    try {
      if (row._id) await axios.delete(`/api/observations/${row._id}`);
      setRows(r => r.filter((_, i) => i !== index));
      showMsg('Row deleted');
    } catch (e) {
      showMsg('Error deleting', 'error');
    }
  };

  if (!context) return null;

  const closedCount = rows.filter(r => r.status === 'Closed').length;
  const openCount = rows.filter(r => r.status === 'Open').length;
  const inProgressCount = rows.filter(r => r.status === 'In Progress').length;

  return (
    <div className="db-bg">
      <div className="db-header">
        <div className="db-header-left">
          <div className="db-logo">AuditPro</div>
          <div className="db-context">
            <span className="ctx-chip">{context.company}</span>
            <span className="ctx-chip">{context.financialYear}</span>
            <span className="ctx-chip">{context.business}</span>
          </div>
        </div>
        <div className="db-header-right">
          <span className="db-welcome">👋 {user?.name}</span>
          <span className="db-role-tag">{user?.role}</span>
          <button onClick={() => navigate('/select')} className="db-back-btn">← Change</button>
          <button onClick={logout} className="db-logout">Logout</button>
        </div>
      </div>

      <div className="db-tabs">
        <button className={`db-tab ${tab === 'create' ? 'active' : ''}`} onClick={() => setTab('create')}>📝 Create</button>
        <button className={`db-tab ${tab === 'report' ? 'active' : ''}`} onClick={() => setTab('report')}>📊 Report</button>
      </div>

      {msg.text && (
        <div className={`db-msg ${msg.type}`}>{msg.type === 'error' ? '⚠' : '✓'} {msg.text}</div>
      )}

      {tab === 'create' && (
        <div className="db-content">
          <div className="db-toolbar">
            <h2>Audit Observations <span className="db-count">{rows.length} rows</span></h2>
            <button className="db-add-btn" onClick={addRow} disabled={saving}>
              {saving ? '...' : '+ Add Row'}
            </button>
          </div>
          {loading ? (
            <div className="db-loading">Loading...</div>
          ) : (
            <div className="db-table-wrap">
              <table className="db-table">
                <thead>
                  <tr>
                    <th>S.No.</th>
                    <th>Fin. Year</th>
                    <th>Business</th>
                    <th>Area</th>
                    <th>Observation</th>
                    <th>Manager Comment</th>
                    <th>Person Resp. as per AC</th>
                    <th>Person Responsible</th>
                    <th>Status</th>
                    <th>Closing Period</th>
                    <th>Closed On</th>
                    <th>Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {rows.length === 0 ? (
                    <tr><td colSpan={12} className="db-empty">No rows yet. Click "+ Add Row" to start.</td></tr>
                  ) : rows.map((row, i) => (
                    <tr key={row._id}>
                      <td className="td-center">{i + 1}</td>
                      <td className="td-auto">{context.financialYear}</td>
                      <td className="td-auto">{context.business}</td>
                      <td>
                        <input className="cell-input" value={row.area}
                          onChange={e => updateCell(i, 'area', e.target.value)}
                          onBlur={() => handleBlur(i)} placeholder="Area..." />
                      </td>
                      <td>
                        <textarea className="cell-textarea" value={row.observation}
                          onChange={e => updateCell(i, 'observation', e.target.value)}
                          onBlur={() => handleBlur(i)} placeholder="Observation..." />
                      </td>
                      <td>
                        <textarea className="cell-textarea" value={row.managerComment}
                          onChange={e => updateCell(i, 'managerComment', e.target.value)}
                          onBlur={() => handleBlur(i)} placeholder="Comment..." />
                      </td>
                      <td>
                        <input className="cell-input" value={row.personResponsibilityAsPerAC}
                          onChange={e => updateCell(i, 'personResponsibilityAsPerAC', e.target.value)}
                          onBlur={() => handleBlur(i)} placeholder="Name..." />
                      </td>
                      <td>
                        <input className="cell-input" value={row.personResponsible}
                          onChange={e => updateCell(i, 'personResponsible', e.target.value)}
                          onBlur={() => handleBlur(i)} placeholder="Name..." />
                      </td>
                      <td>
                        <select className="cell-select" value={row.status}
                          onChange={e => handleStatusChange(i, e.target.value)}>
                          {STATUS_OPTIONS.map(s => <option key={s}>{s}</option>)}
                        </select>
                      </td>
                      <td>
                        <input className="cell-input" value={row.closingPeriod}
                          onChange={e => updateCell(i, 'closingPeriod', e.target.value)}
                          onBlur={() => handleBlur(i)} placeholder="e.g. Q1 2025" />
                      </td>
                      <td>
                        <input className="cell-input" type="date" value={row.closedOn}
                          onChange={e => updateCell(i, 'closedOn', e.target.value)}
                          onBlur={() => handleBlur(i)} />
                      </td>
                      <td className="td-actions">
                        <button className="del-btn" onClick={() => deleteRow(i)}>🗑</button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      )}

      {tab === 'report' && (
        <div className="db-content">
          <div className="db-toolbar">
            <h2>Audit Report</h2>
          </div>
          <div className="report-cards">
            <div className="r-card total"><div className="r-card-num">{rows.length}</div><div className="r-card-label">Total Observations</div></div>
            <div className="r-card open"><div className="r-card-num">{openCount}</div><div className="r-card-label">Open</div></div>
            <div className="r-card inprog"><div className="r-card-num">{inProgressCount}</div><div className="r-card-label">In Progress</div></div>
            <div className="r-card closed"><div className="r-card-num">{closedCount}</div><div className="r-card-label">Closed</div></div>
          </div>
          <div className="db-table-wrap">
            <table className="db-table">
              <thead>
                <tr>
                  <th>S.No.</th><th>Fin. Year</th><th>Business</th><th>Area</th>
                  <th>Observation</th><th>Manager Comment</th><th>Person Resp. as per AC</th>
                  <th>Person Responsible</th><th>Status</th><th>Closing Period</th><th>Closed On</th>
                </tr>
              </thead>
              <tbody>
                {rows.length === 0 ? (
                  <tr><td colSpan={11} className="db-empty">No data yet.</td></tr>
                ) : rows.map((row, i) => (
                  <tr key={row._id}>
                    <td className="td-center">{i + 1}</td>
                    <td>{context.financialYear}</td>
                    <td>{context.business}</td>
                    <td>{row.area}</td>
                    <td>{row.observation}</td>
                    <td>{row.managerComment}</td>
                    <td>{row.personResponsibilityAsPerAC}</td>
                    <td>{row.personResponsible}</td>
                    <td><span className={`status-badge ${row.status.replace(' ', '-').toLowerCase()}`}>{row.status}</span></td>
                    <td>{row.closingPeriod}</td>
                    <td>{row.closedOn}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}
    </div>
  );
}
